from flask import Flask, request, jsonify
import psycopg2
from psycopg2 import sql
from psycopg2.extras import RealDictCursor
import re
from functools import wraps

app = Flask(__name__)

DB_CONFIG = {
    'host': 'localhost',
    'database': 'analytics_db',
    'user': 'your_username',
    'password': 'your_password',
    'port': 5432
}

ALLOWED_TABLES = ['users', 'orders', 'products', 'transactions', 'analytics']
ALLOWED_OPERATORS = ['=', '!=', '>', '<', '>=', '<=', 'LIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL']

def get_db_connection():
    return psycopg2.connect(**DB_CONFIG)

def validate_identifier(identifier):
    if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier):
        raise ValueError(f"Invalid identifier: {identifier}")
    return identifier

def validate_table_name(table_name):
    validate_identifier(table_name)
    if table_name not in ALLOWED_TABLES:
        raise ValueError(f"Table '{table_name}' is not allowed")
    return table_name

def validate_operator(operator):
    operator_upper = operator.upper()
    if operator_upper not in ALLOWED_OPERATORS:
        raise ValueError(f"Operator '{operator}' is not allowed")
    return operator_upper

def error_handler(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except ValueError as e:
            return jsonify({'error': str(e)}), 400
        except psycopg2.Error as e:
            return jsonify({'error': f'Database error: {str(e)}'}), 500
        except Exception as e:
            return jsonify({'error': f'Internal server error: {str(e)}'}), 500
    return decorated_function

